INSERT INTO `cursos` VALUES (681,7,'Fundamentos de IA para el Aula','fundamentos-de-ia-para-el-aula','Este curso introduce a los docentes en el ecosistema de la Inteligencia Artificial, rompiendo mitos y ense├▒ando el uso ├®tico de estas tecnolog├¡as en el entorno escolar.','Aprender├ís la historia de la IA, tipos de modelos (texto, imagen, audio), ├®tica y privacidad de datos de menores, y c├│mo configurar tu primer entorno de trabajo con herramientas gratuitas para el aula.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/6325984/pexels-photo-6325984.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:18:35','Inicia tu camino en la educaci├│n del futuro con IA.',3),(682,7,'Generaci├│n de Material Did├íctico con IA','generacion-de-material-didactico-con-ia','Un taller pr├íctico enfocado en la productividad docente para dise├▒ar diapositivas, infograf├¡as, res├║menes y gu├¡as interactivas utilizando motores de IA.','Dominio de herramientas como Canva Magic, Gamma App, y ChatGPT para la creaci├│n de sesiones de aprendizaje, r├║bricas din├ímicas y contenido multimedia personalizado.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/3183197/pexels-photo-3183197.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:19:06','Crea recursos educativos de alta calidad en tiempo r├®cord.',4),(683,7,'Evaluaci├│n Automatizada y Chatbots Educativos','evaluacion-automatizada-y-chatbots-educativos','Aprende a dise├▒ar sistemas que califiquen autom├íticamente y creen tutores virtuales que acompa├▒en a tus alumnos fuera del horario de clase.','Creaci├│n de GPTs personalizados para tutor├¡a, uso de herramientas como QuestionWell para ex├ímenes inteligentes, y an├ílisis de datos de aprendizaje.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/8363771/pexels-photo-8363771.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:19:44','Automatiza el feedback y personaliza el aprendizaje 24/7.',5),(684,6,'Liderazgo Docente y Comunicaci├│n Efectiva','liderazgo-docente-y-comunicacion-efectiva','Desarrolla habilidades blandas cr├¡ticas para gestionar grupos humanos, manejar expectativas de los padres y liderar con empat├¡a.','T├®cnicas de comunicaci├│n asertiva, gesti├│n de reuniones con padres, liderazgo situacional en el sal├│n y herramientas de organizaci├│n personal para docentes.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/5212345/pexels-photo-5212345.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:22:13','Fortalece tu liderazgo y mejora la relaci├│n con padres y alumnos.',3),(685,6,'Neuroeducaci├│n y Clima Escolar','neuroeducacion-y-clima-escolar','Descubre las bases neurocient├¡ficas del aprendizaje para crear un ambiente escolar seguro, motivador y libre de estr├®s.','Plasticidad cerebral, gesti├│n de las emociones en el aprendizaje, dise├▒o de espacios de aula cerebro-compatibles y estrategias de motivaci├│n intr├¡nseca.',NULL,NULL,'Intermedio',149.00,NULL,20,'https://images.pexels.com/photos/841130/pexels-photo-841130.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:23:00','Entiende c├│mo aprende el cerebro para mejorar la convivencia.',5),(686,6,'Disciplina Positiva y Resoluci├│n de Conflictos','disciplina-positiva-y-resolucion-de-conflictos','Implementa un modelo de convivencia basado en el respeto mutuo, la firmeza y la amabilidad para solucionar problemas de conducta.','Herramientas de disciplina positiva, mediaci├│n entre pares, manejo de conductas disruptivas y creaci├│n de acuerdos de convivencia democr├íticos.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/3184418/pexels-photo-3184418.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-03 23:22:41','Gestiona conflictos en el aula sin castigos ni premios.',4),(687,7,'Planificaci├│n Curricular por Competencias','planificacion-curricular-por-competencias','Domina la estructura de una planificaci├│n efectiva enfocada en lo que el estudiante debe \"saber hacer\".','An├ílisis de est├índares de aprendizaje, redacci├│n de prop├│sitos de aprendizaje, secuencia did├íctica y alineaci├│n entre competencia, capacidad y desempe├▒o.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/5905709/pexels-photo-5905709.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 00:31:34','Dise├▒a sesiones de aprendizaje alineadas al Curr├¡culo Nacional.',3),(688,6,'Metodolog├¡as Activas: Gamificaci├│n y ABP','metodologias-activas-gamificacion-y-abp','Aprende a implementar el Aprendizaje Basado en Proyectos (ABP) y din├ímicas de juego para aumentar el compromiso del alumno.','Dise├▒o de misiones y niveles, uso de mec├ínicas de juego en clase, fases del ABP, y evaluaci├│n de proyectos interdisciplinarios.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/4443160/pexels-photo-4443160.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 01:03:37','Haz que tus alumnos sean los protagonistas de su aprendizaje.',4),(689,8,'Evaluaci├│n Formativa y Dise├▒o de R├║bricas','evaluacion-formativa-y-diseno-de-rubricas','Profundiza en el enfoque de evaluaci├│n formativa, aprendiendo a dar feedback retroalimentador que ayude al alumno a progresar.','Dise├▒o de r├║bricas anal├¡ticas y hol├¡sticas, autoevaluaci├│n y coevaluaci├│n, uso de listas de cotejo y herramientas digitales para la evaluaci├│n en tiempo real.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/5940841/pexels-photo-5940841.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 00:32:19','Eval├║a para aprender, no solo para calificar.',5),(690,10,'Ideaci├│n y Modelo de Negocio Canvas','ideacion-y-modelo-de-negocio-canvas','Un curso fundamental para estructurar ideas de negocio bajo la metodolog├¡a Business Model Canvas, asegurando que cada propuesta tenga un valor real para el mercado.','Definici├│n de propuesta de valor, segmentaci├│n de clientes, canales de distribuci├│n, fuentes de ingresos, estructura de costos y an├ílisis de la competencia en etapas tempranas.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/3184291/pexels-photo-3184291.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 06:39:39','Transforma tu idea en un modelo de negocio rentable.',3),(691,6,'Validaci├│n con MVP y Lean Startup','validacion-con-mvp-y-lean-startup','Aprende a construir Productos M├¡nimos Viables (MVP) para probar tus hip├│tesis con clientes reales antes de hacer grandes inversiones de tiempo y dinero.','Ciclo Construir-Medir-Aprender, dise├▒o de MVPs de baja fidelidad, m├®tricas de validaci├│n, experimentaci├│n con usuarios reales y toma de decisiones basada en datos.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/3184339/pexels-photo-3184339.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 06:39:59','Lanza tu producto al mercado sin gastar miles de soles.',4),(692,6,'Pitch y Levantamiento de Capital','pitch-y-levantamiento-de-capital','Domina el arte de presentar tu negocio ante posibles socios o inversionistas, conociendo los veh├¡culos de inversi├│n que existen hoy en d├¡a.','Dise├▒o de un Pitch Deck profesional, t├®cnicas de oratoria persuasiva, Venture Capital vs. ├üngeles Inversionistas, y t├®rminos legales b├ísicos para el financiamiento.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/3184360/pexels-photo-3184360.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 06:40:23','Convence a inversores y escala tu startup al siguiente nivel.',5),(693,7,'Estrategia de Contenidos y Redes Sociales','estrategia-de-contenidos-y-redes-sociales','Aprende a gestionar comunidades digitales y crear contenido que genere impacto y engagement en las principales plataformas sociales.','Planificaci├│n de contenidos, storytelling para marcas, algoritmos de RRSS (TikTok/Instagram), gesti├│n de crisis en redes y herramientas de dise├▒o para no dise├▒adores.',NULL,NULL,'Principiante',129.00,NULL,16,'https://images.pexels.com/photos/3183150/pexels-photo-3183150.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 20:45:13','Posiciona tu marca y conecta con tu audiencia digital.',4),(694,6,'Performance: Facebook y Google Ads','performance-facebook-y-google-ads','Domina las plataformas de pauta publicitaria m├ís grandes del mundo para atraer tr├ífico cualificado y convertir leads en clientes finales.','Configuraci├│n de Business Manager, segmentaci├│n avanzada, dise├▒o de anuncios de alto impacto, optimizaci├│n de presupuesto y an├ílisis de ROAS (Retorno de Inversi├│n).',NULL,NULL,'Intermedio',149.00,NULL,20,'https://images.pexels.com/photos/3184311/pexels-photo-3184311.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 20:45:36','Maximiza tus ventas con publicidad pagada efectiva.',5),(695,7,'Growth Hacking: Estrategias de Escalado','growth-hacking-estrategias-de-escalado','Implementa metodolog├¡as de crecimiento acelerado basadas en la experimentaci├│n r├ípida y el an├ílisis de datos en cada etapa del embudo.','El embudo pirata (AARRR), experimentos de viralidad, optimizaci├│n de la tasa de conversi├│n (CRO), retenci├│n de usuarios y herramientas de automatizaci├│n de marketing.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/3184325/pexels-photo-3184325.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 20:45:56','Hackea el crecimiento de tu negocio con experimentos creativos.',6),(696,10,'Finanzas para No Financieros','finanzas-para-no-financieros','Un curso pr├íctico para entender la salud financiera de tu empresa sin necesidad de ser un experto contable.','Lectura de estados financieros (Balance y P&L), flujo de caja (Cash Flow), punto de equilibrio, gesti├│n de presupuestos y fijaci├│n de precios rentable.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/53621/pexels-photo-53621.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 21:06:54','Toma el control de los n├║meros de tu negocio con confianza.',3),(697,6,'Gesti├│n de Operaciones y Procesos','gestion-de-operaciones-y-procesos','Dise├▒a y mejora la forma en que tu empresa entrega valor, eliminando cuellos de botella y desperdicios operativos.','Mapeo de procesos, metodolog├¡as Lean, gesti├│n de inventarios y log├¡stica, control de calidad y herramientas de gesti├│n de proyectos.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/3184338/pexels-photo-3184338.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 21:07:16','Optimiza tus procesos para ser m├ís eficiente y escalable.',4),(698,6,'KPIs y Cuadro de Mando Integral','kpis-y-cuadro-de-mando-integral','Aprende a definir indicadores clave de desempe├▒o (KPIs) y construir tableros de control para monitorear tu negocio en tiempo real.','Definici├│n de objetivos OKR y SMART, dise├▒o de Dashboards con herramientas sencillas, interpretaci├│n de m├®tricas de negocio y toma de decisiones estrat├®gicas.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/669615/pexels-photo-669615.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-05 21:07:35','Mide lo que realmente importa para alcanzar tus objetivos.',5),(699,6,'Prompt Engineering para Profesionales','prompt-engineering-para-profesionales','Aprende las t├®cnicas avanzadas de comunicaci├│n con modelos de lenguaje (LLM) para obtener resultados precisos, creativos y t├®cnicos de primer nivel.','Estructura de prompts, t├®cnicas Zero-shot y Few-shot, cadenas de pensamiento (Chain of Thought), y c├│mo evitar alucinaciones en modelos como ChatGPT, Claude y Gemini.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/373543/pexels-photo-373543.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 04:52:32','Domina el arte de hablar con la Inteligencia Artificial.',4),(700,7,'IA para Generaci├│n de Im├ígenes y Video','ia-para-generacion-de-imagenes-y-video','Explora las herramientas l├¡deres en generaci├│n visual para crear campa├▒as de marketing, prototipos de dise├▒o y piezas cinematogr├íficas sin c├ímaras.','Dominio avanzado de Midjourney, Stable Diffusion para control total, Runway Gen-2 para video, y herramientas de edici├│n asistida por IA para retoques.',NULL,NULL,'Intermedio',149.00,NULL,16,'https://images.pexels.com/photos/2599244/pexels-photo-2599244.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 04:52:52','Crea contenido visual hiperrealista con IA.',4),(701,7,'Automatizaci├│n de Tareas con Agentes de IA','automatizacion-de-tareas-with-agentes-de-ia','Descubre c├│mo configurar \"empleados virtuales\" que ejecuten tareas complejas en serie sin intervenci├│n humana constante.','Uso de AutoGPT, configuraci├│n de agentes aut├│nomos en la nube, automatizaci├│n de investigaci├│n de mercado y creaci├│n de flujos de trabajo inteligentes.',NULL,NULL,'Avanzado',149.00,NULL,24,'https://images.pexels.com/photos/3182812/pexels-photo-3182812.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 04:53:12','Pon a trabajar a la IA por ti con agentes aut├│nomos.',6),(702,7,'Introducci├│n a la Automatizaci├│n No-Code','introduccion-a-la-automatizacion-no-code','Aprende a conectar tus herramientas favoritas (Gmail, Drive, Slack) para que trabajen solas y ahorres horas de trabajo manual cada semana.','Conceptos b├ísicos de API, Webhooks, triggers y acciones. Dise├▒o de flujos de trabajo lineales y mentalidad de eficiencia de procesos.',NULL,NULL,'Principiante',99.00,NULL,12,'https://images.pexels.com/photos/2004161/pexels-photo-2004161.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 05:17:36','Automatiza tus primeras tareas sin escribir c├│digo.',3),(703,6,'Flujos de Trabajo Inteligentes con Zapier y Make','flujos-de-trabajo-inteligentes-con-zapier-y-make','Domina las plataformas l├¡deres de automatizaci├│n para construir flujos que incluyan l├│gica condicional y procesamiento de datos mediante IA.','L├│gica condicional avanzada, iteraciones sobre listas de datos, manejo de JSON, y conexi├│n de aplicaciones empresariales cr├¡ticas para el negocio.',NULL,NULL,'Intermedio',129.00,NULL,16,'https://images.pexels.com/photos/2582937/pexels-photo-2582937.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 05:18:01','Crea sistemas de trabajo complejos y potentes.',4),(704,7,'Integraci├│n de APIs de IA en Procesos de Negocio','integracion-de-apis-de-ia-en-procesos-de-negocio','Aprende a integrar los modelos de OpenAI y otros proveedores en tus sistemas actuales para procesar informaci├│n a gran escala de forma autom├ítica.','Consumo t├®cnico de APIs de OpenAI (Vision, Whisper, GPT), procesamiento masivo de informaci├│n, creaci├│n de pipelines de contenido y auditor├¡a de flujos automatizados.',NULL,NULL,'Avanzado',149.00,NULL,20,'https://images.pexels.com/photos/5466231/pexels-photo-5466231.jpeg?auto=compress&cs=tinysrgb&w=800',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-04 05:18:20','Escala tu empresa integrando IA directamente en tus flujos.',5),(705,7,'Python para Ciencia de Datos','python-para-ciencia-de-datos','Inicia desde cero en Python enfocado espec├¡ficamente en el an├ílisis, limpieza y manipulaci├│n de datos cient├¡ficos y estad├¡sticos.','Sintaxis de Python, librer├¡as esenciales (Pandas, NumPy, Matplotlib), limpieza de datos crudos y an├ílisis exploratorio de datos (EDA) para toma de decisiones.',NULL,NULL,'Principiante',149.00,NULL,20,'https://datageeek.com/wp-content/uploads/2025/10/image-1.png',NULL,'Publicado',1,'2026-05-03 22:48:46','2026-05-04 05:47:10','Aprende el lenguaje de programaci├│n de la Inteligencia Artificial.',5),(706,6,'Algoritmos de Machine Learning Supervisado','algoritmos-de-machine-learning-supervisado','Domina los algoritmos cl├ísicos que permiten a las computadoras aprender de datos hist├│ricos para clasificar informaci├│n o predecir valores num├®ricos.','Regresi├│n lineal y log├¡stica, ├írboles de decisi├│n, Random Forest, SVM, m├®tricas de desempe├▒o y t├®cnicas para evitar el overfitting.',NULL,NULL,'Intermedio',179.00,NULL,20,'https://i.pinimg.com/1200x/89/b5/14/89b514e0165455ac9ba95e6ad3c11860.jpg',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-06 03:39:11','Ense├▒a a las m├íquinas a predecir resultados futuros.',5),(707,6,'Deep Learning y Redes Neuronales','deep-learning-y-redes-neuronales','Aprende a construir redes neuronales complejas que imitan el cerebro humano para procesar im├ígenes, texto y sonido de forma avanzada.','Redes Neuronales Artificiales (ANN), Redes Convolucionales (CNN) para visi├│n, procesamiento de lenguaje natural y uso de frameworks como TensorFlow o PyTorch.',NULL,NULL,'Avanzado',219.00,NULL,24,'https://i.pinimg.com/1200x/50/84/10/5084104b7d2077418a4d7d28c4772798.jpg',NULL,'Publicado',0,'2026-05-03 22:48:46','2026-05-06 03:27:55','Entra al mundo del aprendizaje profundo y la visi├│n artificial.',6),(708,6,'Frontend con React y Tailwind','frontend-con-react-y-tailwind','Domina la librer├¡a l├¡der del mercado para crear interfaces de usuario reactivas, utilizando las mejores pr├ícticas de dise├▒o contempor├íneo y optimizaci├│n de rendimiento.','Hooks avanzados, gesti├│n de estado con Context API o Redux Toolkit, animaciones con Framer Motion, estilado 